import { B as Beliefs } from './client-IVkquQfr.js';
import 'zod';

/**
 * Vercel AI SDK middleware for beliefs.
 *
 * Wraps generateText/streamText to automatically call
 * beliefs.before() and beliefs.after() on every model invocation.
 *
 * @example
 * ```ts
 * import { generateText, wrapLanguageModel } from 'ai'
 * import { anthropic } from '@ai-sdk/anthropic'
 * import Beliefs from 'beliefs'
 * import { beliefsMiddleware } from 'beliefs/vercel-ai'
 *
 * const beliefs = new Beliefs({ apiKey: process.env.BELIEFS_KEY })
 *
 * const { text } = await generateText({
 *   model: wrapLanguageModel({
 *     model: anthropic('claude-sonnet-4-20250514'),
 *     middleware: beliefsMiddleware(beliefs),
 *   }),
 *   prompt: 'Research the AI tools market',
 * })
 * ```
 */

type CaptureMode = 'response' | 'tools' | 'all';
interface BeliefsMiddlewareOptions {
    /** What to extract beliefs from. Default: 'response'. */
    capture?: CaptureMode;
    /** Inject belief context into system prompt. Default: true. */
    includeContext?: boolean;
}
declare function beliefsMiddleware(beliefs: Beliefs, options?: BeliefsMiddlewareOptions): {
    specificationVersion: "v3";
    transformParams: ({ params, type: _type, }: {
        type: "generate" | "stream";
        params: Record<string, unknown>;
        model: unknown;
    }) => Promise<Record<string, unknown>>;
    wrapGenerate: ({ doGenerate, params, }: {
        doGenerate: () => Promise<Record<string, unknown>>;
        doStream: () => Promise<unknown>;
        params: Record<string, unknown>;
        model: unknown;
    }) => Promise<Record<string, unknown>>;
    wrapStream: ({ doStream, }: {
        doGenerate: () => Promise<unknown>;
        doStream: () => Promise<Record<string, unknown>>;
        params: Record<string, unknown>;
        model: unknown;
    }) => Promise<Record<string, unknown>>;
};

export { type BeliefsMiddlewareOptions, type CaptureMode, beliefsMiddleware };
